    // Add image from URL,


    addImageFromURL: async function() {
        const urlInput = document.getElementById('image-url-input');
        const url = urlInput?.value?.trim();

        if (!url) {
            toast.error('Please enter an image URL');
            return;
        }

        // Validate URL format
        if (!url.match(/\.(jpg|jpeg|png)$/i)) {
            toast.error('URL must end with .jpg, .jpeg, or .png');
            return;
        }

        try {
            // Fetch the image and convert to blob
            const response = await fetch(url);
            if (!response.ok) {
                throw new Error('Failed to fetch image');
            }

            const blob = await response.blob();
            const file = new File([blob], 'image-from-url.jpg', { type: blob.type });

            // Add to files
            this.processFiles([file], 'add');

            // Clear input
            urlInput.value = '';
            toast.success('Image added successfully!');
        } catch (error) {
            console.error('Error adding image from URL:', error);
            toast.error('Failed to load image. Please check the URL and try again.');
        }
    },

    // Enable clipboard paste for images,


    enableClipboardPaste: function() {
        const clipboardPane = document.querySelector('[data-tab="clipboard"]');
        if (!clipboardPane) return;

        // Remove existing listener if any
        if (this._clipboardListener) {
            document.removeEventListener('paste', this._clipboardListener);
        }

        // Add new listener
        this._clipboardListener = (event) => {
            const items = event.clipboardData?.items;
            if (!items) return;

            for (let i = 0; i < items.length; i++) {
                if (items[i].type.indexOf('image') !== -1) {
                    const blob = items[i].getAsFile();
                    const file = new File([blob], 'pasted-image.png', { type: blob.type });
                    this.processFiles([file], 'add');
                    toast.success('Image pasted successfully!');
                    event.preventDefault();
                    break;
                }
            }
        };

        document.addEventListener('paste', this._clipboardListener);
    },

