    // Save item as draft,


    saveItemAsDraft: async function(event, destination = 'vaultlister') {
        event.preventDefault();

        const form = document.getElementById('add-item-form');
        if (!form) return;

        // Close the dropdown
        document.querySelectorAll('.dropdown.open').forEach(d => d.classList.remove('open'));

        // Validate required fields
        if (!form.checkValidity()) {
            form.reportValidity();
            return;
        }

        // Get form data
        const formData = new FormData(form);
        const itemData = {};
        formData.forEach((value, key) => {
            itemData[key] = value;
        });

        // Add variations
        const variations = (store.state.itemVariations || []).map(v => v.value).filter(v => v);
        if (variations.length > 0) {
            itemData.variations = JSON.stringify(variations);
        }

        // Set status to draft
        itemData.status = 'draft';
        itemData.source = 'manual';
        itemData.draftDestination = destination; // Track where draft is saved

        // Handle images
        const files = this._selectedFiles['add'] || [];
        if (files.length > 0) {
            // Upload images first
            try {
                await api.ensureCSRFToken();
                const uploadedImages = await this.uploadImages(files);
                itemData.images = JSON.stringify(uploadedImages);
            } catch (error) {
                console.error('Error uploading images:', error);
                toast.error('Failed to upload images');
                return;
            }
        }

        try {
            await api.ensureCSRFToken();
            await api.post('/inventory', itemData);

            // Show destination-specific success message
            const messages = {
                vaultlister: 'Item saved as draft in VaultLister',
                platforms: 'Item saved and pushed as draft to platforms',
                both: 'Item saved locally and pushed as draft to platforms'
            };
            toast.success(messages[destination] || 'Item saved as draft!');

            // If pushing to platforms, trigger draft listing creation
            if (destination === 'platforms' || destination === 'both') {
                toast.info('Platform draft sync will be available with connected shops');
            }

            modals.close();

            // Reset variations
            store.setState({ itemVariations: [] });
            this._selectedFiles['add'] = [];

            // Reload inventory
            await this.loadInventory();
            if (store.state.currentPage === 'inventory') {
                renderApp(window.pages.inventory());
            }
        } catch (error) {
            console.error('Error saving draft:', error);
            toast.error('Failed to save draft');
        }
    },


