    async addItem(event) {
        event.preventDefault();
        const form = event.target;
        const formData = new FormData(form);

        let category = formData.get('category');
        if (category === 'other') {
            category = formData.get('customCategory') || '';
        }

        // Convert images to base64
        const imageInput = document.getElementById('item-images-input');
        const images = [];
        if (imageInput && imageInput.files.length > 0) {
            for (let i = 0; i < Math.min(imageInput.files.length, 24); i++) {
                const file = imageInput.files[i];
                if (file.size > 10 * 1024 * 1024) continue; // Skip files over 10MB
                const base64 = await handlers.fileToBase64(file);
                images.push(base64);
            }
        }

        // Get variations
        const variations = (store.state.itemVariations || []).map(v => v.value).filter(v => v);

        // Get quantity and low stock threshold
        const quantity = Math.max(1, Math.round(parseFloat(formData.get('quantity')))) || 1;
        const lowStockThreshold = parseInt(formData.get('lowStockThreshold')) || 5;

        const item = {
            title: formData.get('title'),
            sku: formData.get('sku') || null,  // Will be auto-generated on backend if null and default rule exists
            brand: formData.get('brand'),
            category: category,
            size: formData.get('size'),
            color: formData.get('color'),
            condition: formData.get('condition'),
            costPrice: parseFloat(formData.get('costPrice')) || 0,
            listPrice: parseFloat(formData.get('listPrice')),
            quantity: quantity,
            lowStockThreshold: lowStockThreshold,
            description: formData.get('description'),
            images: JSON.stringify(images),
            variations: variations.length > 0 ? JSON.stringify(variations) : null,
            ebayPromotionRate: parseFloat(formData.get('ebayPromotionRate')) || null,
            ebayPromotionType: formData.get('ebayPromotionType') || null,
            imageCropRatio: formData.get('imageCropRatio') || '1:1',
            status: 'active',
            source: 'manual'
        };

        try {
            // Ensure we have a CSRF token
            await api.ensureCSRFToken();

            const result = await api.post('/inventory', item);
            store.setState({
                inventory: [...store.state.inventory, result.item]
            });

            modals.close();
            toast.success('Item added successfully!');

            // Reset variations
            store.setState({ itemVariations: [] });
            this._selectedFiles['add'] = [];

            await handlers.loadInventory();

            // Re-render inventory page to show new item
            if (store.state.currentPage === 'inventory') {
                const pageContent = window.pages.inventory();
                document.querySelector('.page-content').innerHTML = sanitizeHTML(pageContent);  // nosemgrep: javascript.browser.security.insecure-document-method.insecure-document-method
            }
        } catch (error) {
            toast.error(error.message);
        }
    },


    async updateItem(event, itemId) {
        event.preventDefault();
        const form = event.target;
        const formData = new FormData(form);

        // Get existing item to retrieve current images
        const item = store.state.inventory.find(i => i.id === itemId);
        let existingImages = [];
        if (item && item.images) {
            existingImages = Array.isArray(item.images) ? item.images : JSON.parse(item.images);
        }

        // Remove marked images
        const removedIndices = formData.get('removedImages');
        if (removedIndices) {
            const indicesToRemove = removedIndices.split(',').map(i => parseInt(i, 10)).filter(i => !isNaN(i));
            existingImages = existingImages.filter((_, idx) => !indicesToRemove.includes(idx));
        }

        // Add new images
        const imageInput = document.getElementById('edit-item-images-input');
        if (imageInput && imageInput.files.length > 0) {
            for (let i = 0; i < Math.min(imageInput.files.length, 3 - existingImages.length); i++) {
                const file = imageInput.files[i];
                if (file.size > 5 * 1024 * 1024) continue; // Skip files over 5MB
                const base64 = await handlers.fileToBase64(file);
                existingImages.push(base64);
            }
        }

        const updates = {
            title: formData.get('title'),
            sku: formData.get('sku') || null,
            brand: formData.get('brand'),
            category: formData.get('category'),
            size: formData.get('size'),
            color: formData.get('color'),
            condition: formData.get('condition'),
            costPrice: parseFloat(formData.get('costPrice')) || 0,
            listPrice: parseFloat(formData.get('listPrice')),
            quantity: Math.max(1, Math.round(parseFloat(formData.get('quantity')))) || 1,
            lowStockThreshold: parseInt(formData.get('lowStockThreshold')) || 5,
            description: formData.get('description'),
            status: formData.get('status'),
            notes: formData.get('notes'),
            images: existingImages
        };

        try {
            // Ensure we have a CSRF token
            await api.ensureCSRFToken();

            try {
                await api.put(`/inventory/${itemId}`, updates);
            } catch (putError) {
                // If item not found in DB (e.g. demo/mock item), create it instead
                if (putError.message && (putError.message.includes('404') || putError.message.includes('not found') || putError.message.includes('Not found'))) {
                    await api.post('/inventory', updates);
                } else {
                    throw putError;
                }
            }
            modals.close();
            toast.success('Item updated successfully!');
            await handlers.loadInventory();

            // Re-render inventory page using renderApp for proper state handling
            if (store.state.currentPage === 'inventory') {
                renderApp(window.pages.inventory());
            }
        } catch (error) {
            toast.error(error.message);
        }
    },

