    // Sorting

    currentSort: { field: 'created_at', direction: 'desc' },


    toggleSort: async function(field) {
        // Debounce rapid clicks
        if (handlers._sortTimeout) {
            return; // Ignore if already processing
        }

        let direction = 'asc';
        if (handlers.currentSort?.field === field) {
            direction = handlers.currentSort?.direction === 'asc' ? 'desc' : 'asc';
        }

        handlers.currentSort = { field, direction };
        handlers._sortTimeout = setTimeout(() => {
            handlers._sortTimeout = null;
        }, 300);

        try {
            // Age sorting is inverse of created_at (older items = higher age)
            const sortVersion = ++handlers._sortVersion;
            const ageDirection = direction === 'asc' ? 'desc' : 'asc';
            const sortParam = field === 'list_price' ? `price_${direction}` :
                             field === 'created_at' ? `created_${direction}` :
                             field === 'age' ? `created_${ageDirection}` :
                             field === 'title' ? `title_${direction}` :
                             field === 'sku' ? `sku_${direction}` :
                             field === 'status' ? `status_${direction}` :
                             field === 'marketplace' ? `marketplace_${direction}` :
                             field === 'tags' ? `tags_${direction}` :
                             field === 'stock_level' ? `quantity_${direction}` :
                             `${field}_${direction}`;
            const data = await api.get(`/inventory?sort=${sortParam}&limit=200`);
            if (sortVersion !== handlers._sortVersion) return;
            store.setState({ inventory: data.items });

            // Re-render inventory page
            if (store.state.currentPage === 'inventory') {
                const pageContent = window.pages.inventory();
                const container = document.querySelector('.page-content');
                if (container) container.innerHTML = sanitizeHTML(pageContent);  // nosemgrep: javascript.browser.security.insecure-document-method.insecure-document-method

            }
        } catch (error) {
            toast.error(error.message);
        }
    },

