    updateListing: async function(event, listingId) {
        event.preventDefault();
        const form = event.target;
        const formData = new FormData(form);

        const updates = {
            title: formData.get('title'),
            description: formData.get('description'),
            price: parseFloat(formData.get('price')) || null,
            shipping_price: parseFloat(formData.get('shipping_price')) || 0,
            status: formData.get('status'),
            category_path: formData.get('category_path') || null,
            condition_tag: formData.get('condition_tag') || null,
            notes: formData.get('notes') || null
        };

        try {
            await api.ensureCSRFToken();
            await api.put(`/listings/${listingId}`, updates);
            modals.close();
            toast.success('Listing updated successfully!');
            await handlers.loadListings();

            if (store.state.currentPage === 'listings') {
                const pageContent = pages.listings();
                document.querySelector('.page-content').innerHTML = sanitizeHTML(pageContent);  // nosemgrep: javascript.browser.security.insecure-document-method.insecure-document-method
            }
        } catch (error) {
            toast.error('Failed to update listing: ' + error.message);
        }
    },


    archiveListing: async function(listingId) {
        const listing = (store.state.listings || []).find(l => l.id === listingId);
        if (!listing) {
            toast.error('Listing not found');
            return;
        }

        if (!await modals.confirm(`Archive listing "${listing.title}" on ${listing.platform}?`, { title: 'Archive Listing', confirmText: 'Archive' })) {
            return;
        }

        try {
            await api.ensureCSRFToken();
            await api.post(`/listings/${listingId}/archive`, {});
            toast.success('Listing archived successfully!');
            await handlers.loadListings();

            // Re-render listings page using renderApp for proper state handling
            if (store.state.currentPage === 'listings') {
                renderApp(pages.listings());
            }
        } catch (error) {
            toast.error('Failed to archive listing: ' + error.message);
        }
    },


