    updatePlatformPanels: function() {
        const platformCheckboxes = document.querySelectorAll('.platform-checkbox');
        const selectedPlatforms = Array.from(platformCheckboxes)
            .filter(cb => cb.checked)
            .map(cb => cb.value);

        const panels = document.querySelectorAll('.platform-customization-panel');
        panels.forEach(panel => {
            const platform = panel.getAttribute('data-platform');
            if (selectedPlatforms.includes(platform)) {
                panel.classList.remove('hidden');
            } else {
                panel.classList.add('hidden');
            }
        });
    },


    applyPriceAdjustment: function(platform, adjustPercent, basePrice) {
        const priceInput = document.querySelector(`input[name="${platform}Price"]`);
        if (!priceInput) return;

        const adjustment = parseFloat(adjustPercent) / 100;
        const newPrice = basePrice * (1 + adjustment);
        priceInput.value = newPrice.toFixed(2);
    },

    // ========================================
    // AI Listing Generator
    // ========================================,


    handleAIImageSelect: function(event) {
        const file = event.target.files[0];
        if (!file) return;

        // Validate file size (max 5MB)
        if (file.size > 5 * 1024 * 1024) {
            toast.error('Image too large. Maximum 5MB.');
            return;
        }

        // Validate file type
        if (!['image/jpeg', 'image/png'].includes(file.type)) {
            toast.error('Please select a JPEG or PNG image.');
            return;
        }

        // Show preview
        const reader = new FileReader();
        reader.onload = (e) => {
            const preview = document.getElementById('ai-preview-img');
            const previewContainer = document.getElementById('ai-image-preview');
            if (preview && previewContainer) {
                preview.src = e.target.result;
                previewContainer.classList.remove('hidden');
            }

            // Store image data for AI analysis
            this._aiImageData = {
                base64: e.target.result.split(',')[1], // Remove data:image/...;base64, prefix
                mimeType: file.type
            };

            // Enable analyze button
            const analyzeBtn = document.getElementById('ai-analyze-btn');
            if (analyzeBtn) analyzeBtn.removeAttribute('disabled');
        };
        reader.readAsDataURL(file);
    },


    startAIAnalysis: async function() {
        if (!this._aiImageData) {
            return toast.error('Please select an image first');
        }

        const platform = document.getElementById('ai-target-platform')?.value || 'poshmark';

        // Show loading step
        document.getElementById('ai-wizard-step-1')?.classList.add('hidden');
        document.getElementById('ai-wizard-step-2')?.classList.remove('hidden');
        document.getElementById('ai-analyze-btn')?.classList.add('hidden');

        try {
            await api.ensureCSRFToken();
            const response = await api.post('/ai/analyze-listing-image', {
                imageBase64: this._aiImageData.base64,
                imageMimeType: this._aiImageData.mimeType,
                platform: platform
            });

            // Store generated data (unwrap analysis if nested)
            const analysisData = response.analysis || response;
            this._aiGeneratedData = analysisData;

            // Show results step
            document.getElementById('ai-wizard-step-2')?.classList.add('hidden');
            document.getElementById('ai-wizard-step-3')?.classList.remove('hidden');
            document.getElementById('ai-apply-btn')?.classList.remove('hidden');

            // Display results
            this.displayAIResults(analysisData);

        } catch (error) {
            // Show error and return to step 1
            document.getElementById('ai-wizard-step-2')?.classList.add('hidden');
            document.getElementById('ai-wizard-step-1')?.classList.remove('hidden');
            document.getElementById('ai-analyze-btn')?.classList.remove('hidden');

            toast.error(error.message || 'AI analysis failed. Please try again.');
            console.error('AI analysis error:', error);
        }
    },


