    // NOTE: loadHeatmapData, loadMarketIntel, loadPredictions, loadPushStatus,
    // loadSuppliers, loadWebhooks are defined earlier (~line 53574) with full
    // filter params, Promise.all calls, and proper toast notifications.

    // Load Whatnot events,


    showItemOfferHistory: function() {
        const offers = store.state.offers || [];
        const listings = store.state.listings || [];

        // Group offers by listing_id
        const grouped = {};
        offers.forEach(o => {
            const key = o.listing_id || o.item_title || 'Unknown';
            if (!grouped[key]) {
                const listing = listings.find(l => l.id === o.listing_id);
                grouped[key] = {
                    title: listing?.title || o.item_title || 'Unknown Item',
                    listing_price: listing?.price || o.listing_price || 0,
                    platform: listing?.platform || o.platform || '',
                    offers: []
                };
            }
            grouped[key].offers.push(o);
        });

        const items = Object.values(grouped).sort((a, b) => b.offers.length - a.offers.length);
        const totalItems = items.length;
        const mostNegotiated = items[0];
        const totalAccepted = offers.filter(o => o.status === 'accepted').length;
        const overallRate = offers.length > 0 ? Math.round((totalAccepted / offers.length) * 100) : 0;

        modals.show(`
            <div class="modal-header">
                <h2 class="modal-title">${components.icon('clock', 20)} Offer History by Item</h2>
                <button class="modal-close" aria-label="Close" onclick="modals.close()">${components.icon('close')}</button>
            </div>
            <div class="modal-body item-offer-history">
                <div class="offer-history-summary">
                    <div class="stat-card">
                        <div class="stat-value">${totalItems}</div>
                        <div class="stat-label">Items with Offers</div>
                    </div>
                    <div class="stat-card">
                        <div class="stat-value">${mostNegotiated ? mostNegotiated.offers.length : 0}</div>
                        <div class="stat-label">Most Offers (Single Item)</div>
                    </div>
                    <div class="stat-card">
                        <div class="stat-value">${overallRate}%</div>
                        <div class="stat-label">Overall Accept Rate</div>
                    </div>
                </div>

                ${items.length === 0 ? '<p class="text-center text-gray-500 py-8">No offer history yet</p>' : items.map((item, idx) => {
                    const accepted = item.offers.filter(o => o.status === 'accepted').length;
                    const declined = item.offers.filter(o => o.status === 'declined' || o.status === 'rejected').length;
                    const pending = item.offers.filter(o => o.status === 'pending').length;
                    const avgOffer = item.offers.reduce((s, o) => s + (o.amount || 0), 0) / item.offers.length;
                    const avgPct = item.listing_price > 0 ? Math.round((avgOffer / item.listing_price) * 100) : 0;

                    return `
                        <div class="item-offer-group">
                            <div class="item-offer-header" onclick="this.parentElement.classList.toggle('expanded')">
                                <div class="item-offer-info">
                                    <strong>${escapeHtml(item.title)}</strong>
                                    ${item.platform ? '<span class="badge badge-gray ml-2">' + escapeHtml(item.platform) + '</span>' : ''}
                                </div>
                                <div class="item-offer-stats">
                                    <span class="badge badge-primary">${item.offers.length} offer${item.offers.length !== 1 ? 's' : ''}</span>
                                    ${accepted > 0 ? '<span class="badge badge-success">' + accepted + ' accepted</span>' : ''}
                                    ${declined > 0 ? '<span class="badge badge-error">' + declined + ' declined</span>' : ''}
                                    ${pending > 0 ? '<span class="badge badge-warning">' + pending + ' pending</span>' : ''}
                                    <span class="text-sm text-gray-500">Avg: $${avgOffer.toFixed(0)} (${avgPct}%)</span>
                                    ${components.icon('chevron-down', 16)}
                                </div>
                            </div>
                            <div class="item-offer-details">
                                ${item.offers.sort((a, b) => new Date(b.created_at || 0) - new Date(a.created_at || 0)).map(o => {
                                    const date = o.created_at ? new Date(o.created_at).toLocaleDateString() : 'Unknown';
                                    const statusClass = o.status === 'accepted' ? 'success' : o.status === 'declined' || o.status === 'rejected' ? 'error' : 'warning';
                                    return '<div class="offer-timeline-entry">' +
                                        '<div class="offer-timeline-date">' + date + '</div>' +
                                        '<div class="offer-timeline-amount">$' + (o.amount || 0).toFixed(2) + '</div>' +
                                        '<span class="badge badge-' + statusClass + '">' + escapeHtml(o.status || 'pending') + '</span>' +
                                        (o.buyer_username ? '<span class="text-xs text-gray-500">' + escapeHtml(o.buyer_username) + '</span>' : '') +
                                    '</div>';
                                }).join('')}
                            </div>
                        </div>
                    `;
                }).join('')}
            </div>
            <div class="modal-footer">
                <button class="btn btn-secondary" onclick="modals.close()">Close</button>
            </div>
        `, 'modal-lg');
    },

    // Checklist Analytics,


    setAcquiredDate: async function(itemId) {
        const date = await modals.prompt('Select the date this item was acquired:', { title: 'Set Acquired Date', inputType: 'date' });
        if (!date) return;
        try {
            const res = await fetch(`/api/inventory/${itemId}`, {
                method: 'PUT',
                headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${store.state.token}`, 'x-csrf-token': store.state.csrfToken },
                body: JSON.stringify({ acquired_date: date })
            });
            if (res.ok) { toast.success('Acquired date set'); await handlers.loadInventory(); }
        } catch (err) { toast.error('Failed to update'); }
    },

